module RefModule(  
    input [79:0] data, // 5 x 16-bit data  
    output reg [15:0] checksum  
);  
    integer obf_i;  
    reg [31:0] sum;  

    always @(*) begin  
        sum = 0;  
        for (obf_i = 0; obf_i < 5; obf_i = obf_i + 1) begin  
            sum = sum + data[16*obf_i +: 16];  
        end  
        // Add carry  
        sum = (sum >> 16) + (sum & 16'hFFFF);  
        // One's complement  
        checksum = ~sum[15:0];  
    end  
endmodule
